mapper.select:
SELECT al.id ,al.security_code ,al.security_short_name ,al.security_type ,dst.security_type_name ,sb.issuer ,al.adjust_type ,al.adjust_mode ,al.target_pool_id ,al.adjust_batch_no ,p.pool_name AS target_pool_path ,al.pool_type ,al.audit_status ,al.adjuster_name ,al.adjust_reason ,al.submit_time FROM ip_adjust_log al LEFT JOIN ip_investment_pool p ON p.id = al.target_pool_id AND p.is_deleted = 0 LEFT JOIN rrs_securityinfo sb ON sb.wind_code = al.security_code LEFT JOIN dict_security_type dst ON dst.security_type = al.security_type AND dst.is_deleted = 0
al.is_deleted = 0 AND al.pool_type NOT IN ('crmw', 'forbidden')
AND al.target_pool_id IN
#{id}
AND al.security_code LIKE CONCAT('%', #{securityCode}, '%')
AND al.security_short_name LIKE CONCAT('%', #{securityShortName}, '%')
AND al.security_type = #{securityType}
AND (CASE WHEN sb.maturity_date IS NOT NULL AND sb.maturity_date < DATE_FORMAT(NOW(), '%Y-%m-%d') THEN '到期' ELSE '存续' END) = #{securityStatus}
AND al.submit_time >= #{adjustTimeStart}
AND al.submit_time <= CONCAT(#{adjustTimeEnd}, ' 23:59:59')
AND al.adjuster_name LIKE CONCAT('%', #{adjusterName}, '%')
AND sb.issuer LIKE CONCAT('%', #{issuer}, '%')
AND al.adjust_mode = #{adjustMode}
AND al.audit_status = #{auditStatus}
AND al.adjuster_id = #{currentUserId}
ORDER BY al.submit_time DESC ,al.adjust_batch_no DESC ,al.id DESC
